// Scope checking middleware factory
function requireScope(...requiredScopes) {
  return (req, res, next) => {
    if (!req.auth || !req.auth.scope) {
      return res.status(403).json({
        error: 'insufficient_scope',
        error_description: 'Token does not contain required scopes',
        required_scopes: requiredScopes,
      });
    }

    const hasAllScopes = requiredScopes.every(scope => req.auth.scope.includes(scope));

    if (!hasAllScopes) {
      return res.status(403).json({
        error: 'insufficient_scope',
        error_description: 'Token does not contain required scopes',
        required_scopes: requiredScopes,
      });
    }

    next();
  };
}

